async function saveTrip(
  trip: Trip,
  expectedVersion?: number
): Promise<string> {
  if (expectedVersion !== undefined) {
    const current = await getTrip(trip.userId, trip.id)
    if (current && current.version !== expectedVersion) {
      throw new VersionConflictError(current)
    }
  }

  const tripToSave: Trip = {
    ...trip,
    version: (trip.version ?? 0) + 1,
    updatedAt: new Date().toISOString(),
  }

  const path = tripPath(tripToSave.userId, tripToSave.id)
  const encrypted = encryptTripPII(tripToSave)
  const blob = await put(path, JSON.stringify(encrypted), {
    access: "private",
    contentType: "application/json",
    addRandomSuffix: false,
  })
  return blob.url
}
